    private static void normalizeMcdProfileDecorChildParams(Activity activity) {
        if (activity == null || activity.getWindow() == null) {
            return;
        }
        try {
            android.view.View decor = activity.getWindow().getDecorView();
            if (!(decor instanceof android.widget.FrameLayout)) {
                return;
            }
            android.widget.FrameLayout frame = (android.widget.FrameLayout) decor;
            int count = frame.getChildCount();
            for (int i = 0; i < count; i++) {
                android.view.View child = frame.getChildAt(i);
                if (child == null) {
                    continue;
                }
                android.view.ViewGroup.LayoutParams lp = child.getLayoutParams();
                if (!(lp instanceof android.widget.FrameLayout.LayoutParams)) {
                    child.setLayoutParams(new android.widget.FrameLayout.LayoutParams(
                            android.view.ViewGroup.LayoutParams.MATCH_PARENT,
                            android.view.ViewGroup.LayoutParams.MATCH_PARENT));
                }
            }
        } catch (Throwable t) {
            startupLog("[WestlakeLauncher] McD profile decor param normalize error", t);
        }
    }

    private static void layoutDecorForHeight(Activity activity, int height, String label) {
        if (activity == null || activity.getWindow() == null) {
            return;
        }
        try {
            android.view.View decor = activity.getWindow().getDecorView();
            if (decor == null) {
                return;
            }
            int wSpec = android.view.View.MeasureSpec.makeMeasureSpec(
                    SURFACE_WIDTH, android.view.View.MeasureSpec.EXACTLY);
            int hSpec = android.view.View.MeasureSpec.makeMeasureSpec(
                    height, android.view.View.MeasureSpec.EXACTLY);
            decor.measure(wSpec, hSpec);
            decor.layout(0, 0, SURFACE_WIDTH, height);
        } catch (Throwable t) {
            startupLog("[WestlakeLauncher] " + label + " layout error", t);
            logThrowableFrames("[WestlakeLauncher] " + label + " layout", t, 8);
            try {
                android.view.View decor = activity.getWindow().getDecorView();
                fallbackLayoutTree(decor, 0, 0, SURFACE_WIDTH, height, 0);
            } catch (Throwable fallbackError) {
                startupLog("[WestlakeLauncher] " + label + " fallback layout error",
                        fallbackError);
            }
        }
    }

