    /**
     * Build a visible McDonald's dashboard UI on the activity's content view.
     * Uses the real base_layout container and adds mock menu content.
     */
    public static void populateDashboardFallback(Activity activity) {
        if (isDashboardFallbackInstalled(activity)) {
            startupLog("[WestlakeLauncher] Dashboard fallback already installed for "
                    + activity.getClass().getName());
            return;
        }
        sDirectDashboardFallbackActive = false;
        try {
            boolean textOnlyFallback = shouldUseTextOnlyDashboardMenu(activity);
            if (!textOnlyFallback && !isDashboardSyntheticFallbackEnabled()) {
                startupLog("[WestlakeLauncher] Dashboard synthetic fallback skipped by default");
                appendCutoffCanaryMarker("MCD_DASH_FALLBACK_SKIPPED reason=default_real_probe");
                return;
            }
            if (textOnlyFallback) {
                drawTextOnlyDashboardMenu();
                markDashboardFallbackInstalled(activity);
                return;
            }
            if (installDashboardViewFallback(activity)) {
                markDashboardFallbackInstalled(activity);
                startupLog("[WestlakeLauncher] Dashboard fallback UI populated in container");
                return;
            }
            if (activity == null || !OHBridge.isNativeAvailable()) {
                return;
            }
            long surf = OHBridge.surfaceCreate(0, SURFACE_WIDTH, SURFACE_HEIGHT);
            long canv = OHBridge.surfaceGetCanvas(surf);
            long font = OHBridge.fontCreate();
            long pen = OHBridge.penCreate();
            long brush = OHBridge.brushCreate();

            OHBridge.canvasDrawColor(canv, 0xFFF5F5F5);

            OHBridge.fontSetSize(font, 30);
            OHBridge.penSetColor(pen, 0xFFDA291C);
            OHBridge.canvasDrawText(canv, "McDonald's", 36, 90, font, pen, brush);

            OHBridge.fontSetSize(font, 18);
            OHBridge.penSetColor(pen, 0xFF333333);
            OHBridge.canvasDrawText(canv, "Dashboard fallback", 36, 130, font, pen, brush);

            OHBridge.fontSetSize(font, 20);
            OHBridge.penSetColor(pen, 0xFF111111);
            OHBridge.canvasDrawText(canv, "Big Mac Combo        $5.99", 36, 220, font, pen, brush);
            OHBridge.canvasDrawText(canv, "2 for $6 Mix & Match", 36, 275, font, pen, brush);
            OHBridge.canvasDrawText(canv, "Free Medium Fries", 36, 330, font, pen, brush);
            OHBridge.canvasDrawText(canv, "McFlurry OREO        $3.49", 36, 385, font, pen, brush);

            OHBridge.fontSetSize(font, 16);
            OHBridge.penSetColor(pen, 0xFF666666);
            OHBridge.canvasDrawText(canv, "Home   Deals   Order   Rewards   More", 24, 730, font, pen, brush);

            OHBridge.surfaceFlush(surf);
            sDirectDashboardFallbackActive = true;
            startupLog("[WestlakeLauncher] Dashboard fallback drawn via OHBridge");
            markDashboardFallbackInstalled(activity);
        } catch (Throwable t) {
            sDirectDashboardFallbackActive = false;
            try { nativePrintException(t); } catch (Throwable ignored) {}
            startupLog("[WestlakeLauncher] populateDashboardFallback error", t);
        }
    }

    private static void renderLoop(Activity initialActivity, MiniActivityManager am) {
        if (android.app.WestlakeActivityThread.pendingDashboardClass != null) {
            String dashClass = android.app.WestlakeActivityThread.pendingDashboardClass;
            android.app.WestlakeActivityThread.pendingDashboardClass = null;
            startupLog("[WestlakeLauncher] Launching pending dashboard: " + dashClass);
            startupLog("[WestlakeLauncher] renderLoop initial before dashboard="
                    + (initialActivity != null ? initialActivity.getClass().getName() : "null"));
            Activity dash = null;
            try {
                android.app.WestlakeActivityThread wat = android.app.WestlakeActivityThread.currentActivityThread();
                Intent dashIntent = new Intent();
                dashIntent.setComponent(new ComponentName("com.mcdonalds.app", dashClass));
                dash = android.app.WestlakeActivityThread.launchActivity(
                        wat, dashClass, "com.mcdonalds.app", dashIntent);
            } catch (Throwable t) {
                startupLog("[WestlakeLauncher] Dashboard launchActivity error", t);
                logThrowableFrames("[WestlakeLauncher] Dashboard launchActivity", t, 12);
            }
            if (dash != null) {
                try {
                    Activity previous = initialActivity;
                    initialActivity = dash;
                    startupLog("[WestlakeLauncher] Dashboard active: " + dash.getClass().getName());
                    boolean deferredResumeForFirstFrame =
                            shouldDeferMcdDashboardResumeForFirstFrame(dash, previous);
                    if (deferredResumeForFirstFrame) {
                        startupLog("[WestlakeLauncher] Dashboard performResumeActivity deferred for first frame");
                        appendCutoffCanaryMarker("MCD_DASH_RESUME_DEFERRED reason=strict_first_frame");
                    } else {
                        try {
                            android.app.WestlakeActivityThread.currentActivityThread()
                                    .performResumeActivity(dash);
                            startupLog("[WestlakeLauncher] Dashboard performResumeActivity requested");
                        } catch (Throwable resumeError) {
                            startupLog("[WestlakeLauncher] Dashboard performResumeActivity error",
                                    resumeError);
                            logThrowableFrames("[WestlakeLauncher] Dashboard performResumeActivity",
                                    resumeError, 12);
                        }
                    }
                    Activity resumed = null;
                    try { resumed = am.getResumedActivity(); } catch (Throwable ignored) {}
                    startupLog("[WestlakeLauncher] Dashboard resumed after launch="
                            + (resumed != null ? resumed.getClass().getName() : "null"));
                    ensureMcdDashboardXmlScaffold(dash);
                    boolean fallbackAlreadyInstalled = false;
                    try {
                        fallbackAlreadyInstalled = isDashboardFallbackInstalled(dash);
                    } catch (Throwable installedLookupError) {
                        startupLog("[WestlakeLauncher] Dashboard fallback lookup error", installedLookupError);
                        logThrowableFrames("[WestlakeLauncher] Dashboard fallback lookup",
                                installedLookupError, 8);
                    }
                    if (!fallbackAlreadyInstalled) {
                        try {
                            populateDashboardFallback(dash);
                        } catch (Throwable fallbackError) {
                            startupLog("[WestlakeLauncher] Dashboard fallback install error", fallbackError);
                            logThrowableFrames("[WestlakeLauncher] Dashboard fallback install",
                                    fallbackError, 8);
                        }
                    } else {
                        startupLog("[WestlakeLauncher] Dashboard fallback already present before render loop");
                    }
                    startupLog("[WestlakeLauncher] Dashboard fallback handoff ready");
                    // Let the normal render loop drive the first dashboard frame.
                    // The older eager render/demo path was crashing inside the
                    // guest before the real view tree had stabilized.
                    splashImageData = null;
                    if (previous != null && previous != dash) {
                        boolean firstDashboardPromotion = isHomeDashboardActivity(dash)
                                && !isHomeDashboardActivity(previous);
                        if (firstDashboardPromotion) {
                            startupLog("[WestlakeLauncher] Preserving previous surface for first dashboard handoff");
                        } else {
                            try {
                                previous.onSurfaceDestroyed();
                                startupLog("[WestlakeLauncher] Previous activity surface destroyed");
                            } catch (Throwable previousDestroyError) {
                                startupLog("[WestlakeLauncher] Previous surface destroy error",
                                        previousDestroyError);
                            }
                        }
                    }
                    startupLog("[WestlakeLauncher] Dashboard pre-first-frame direct="
                            + sDirectDashboardFallbackActive);
                    if (!sDirectDashboardFallbackActive) {
                        try {
                            boolean adoptedSurface = false;
                            if (previous != null && previous != dash
                                    && isHomeDashboardActivity(dash)
                                    && !isHomeDashboardActivity(previous)) {
                                try {
                                    adoptedSurface = dash.adoptSurfaceFrom(previous);
                                    startupLog("[WestlakeLauncher] Dashboard adopted previous surface="
                                            + adoptedSurface);
                                } catch (Throwable adoptError) {
                                    startupLog("[WestlakeLauncher] Dashboard surface adopt error",
                                            adoptError);
                                }
                            }
                            if (!adoptedSurface) {
                                dash.onSurfaceCreated(0L, SURFACE_WIDTH, SURFACE_HEIGHT);
                            }
                            if (!FRAMEWORK_POLICY_WESTLAKE_ONLY.equals(frameworkPolicyValue())
                                    || !writeStrictStandaloneViewFrame(dash, "dashboard-first")) {
                                dash.renderFrame();
                            }
                            startupLog("[WestlakeLauncher] Dashboard first frame requested");
                            if (deferredResumeForFirstFrame) {
                                startDeferredMcdDashboardResume(dash);
                            }
                            sDisableHostInputPolling = false;
                            startupLog("[WestlakeLauncher] Host input polling enabled for dashboard frame");
                        } catch (Throwable frameError) {
                            startupLog("[WestlakeLauncher] Dashboard first render error", frameError);
                            logThrowableFrames("[WestlakeLauncher] Dashboard first render", frameError, 8);
                        }
                    } else {
                        startupLog("[WestlakeLauncher] Dashboard frame is direct OHBridge fallback");
                    }
                } catch (Throwable t) {
                    startupLog("[WestlakeLauncher] Dashboard handoff error", t);
                    logThrowableFrames("[WestlakeLauncher] Dashboard handoff", t, 12);
                }
            }
        }

        if (sDirectDashboardFallbackActive) {
            startupLog("[WestlakeLauncher] Direct dashboard fallback active");
            while (true) {
                try { Thread.sleep(1000); } catch (InterruptedException e) { break; }
            }
            return;
        }

        // Check if Activity has our shim methods (onSurfaceCreated/renderFrame)
        boolean hasShimMethods = true;
        try { initialActivity.getClass().getMethod("onSurfaceCreated", long.class, int.class, int.class); }
        catch (NoSuchMethodException e) { hasShimMethods = false; }
        if (initialActivity != null) {
            startupLog("[WestlakeLauncher] renderLoop activity="
                    + initialActivity.getClass().getName()
                    + (hasShimMethods ? " shim=yes" : " shim=no"));
        } else {
            startupLog("[WestlakeLauncher] renderLoop activity=null");
        }

        if (initialActivity != null && hasShimMethods) {
            try {
                String initialName = initialActivity.getClass().getName();
                if (initialName != null && initialName.toLowerCase().contains("dashboard")) {
                    splashImageData = null;
                }
            } catch (Throwable ignored) {
            }
            if (isHomeDashboardActivity(initialActivity)) {
                startupLog("[WestlakeLauncher] renderLoop skipping dashboard surface re-prime");
            } else {
                try {
                    initialActivity.onSurfaceDestroyed();
                } catch (Throwable ignored) {
                }
                try {
                    initialActivity.onSurfaceCreated(0L, SURFACE_WIDTH, SURFACE_HEIGHT);
                    startupLog("[WestlakeLauncher] renderLoop surface primed");
                } catch (Throwable surfaceError) {
                    startupLog("[WestlakeLauncher] renderLoop surface prime error", surfaceError);
                }
            }
        }

        if (!hasShimMethods) {
            startupLog("[WestlakeLauncher] Framework Activity — OHBridge-only render loop");
            // Simple keep-alive loop: the splash was already sent via OHBridge
            // Touch events can still be processed
            while (true) {
                try { Thread.sleep(1000); } catch (InterruptedException e) { break; }
            }
            return;
        }

        long frameCount = 0;
        int lastTouchSeq = -1;
        int lastTextSize = -1;
        int lastTextHash = 0;

        // Prefer WESTLAKE_TOUCH env var (set by Compose host)
        String envTouch = System.getenv("WESTLAKE_TOUCH");
        String touchPath = null;
        if (envTouch != null && !envTouch.isEmpty()) {
            touchPath = envTouch;
            startupLog("[WestlakeLauncher] Touch file (env): " + envTouch);
        } else {
            touchPath = defaultTouchPath();
            startupLog("[WestlakeLauncher] Touch file (default): " + touchPath);
        }
        String touchDir = parentPath(touchPath);
        String textPath = joinPath(touchDir, "westlake_text.dat");

        // After splash: if we have real icons from app_process64, render them
        if (realIconsPng != null && com.ohos.shim.bridge.OHBridge.isNativeAvailable()) {
            try { Thread.sleep(3000); } catch (InterruptedException ignored) {}
            try {
                long surf = com.ohos.shim.bridge.OHBridge.surfaceCreate(0, SURFACE_WIDTH, SURFACE_HEIGHT);
                long canv = com.ohos.shim.bridge.OHBridge.surfaceGetCanvas(surf);
                com.ohos.shim.bridge.OHBridge.canvasDrawImage(canv, realIconsPng, 0, 0, SURFACE_WIDTH, SURFACE_HEIGHT);
                com.ohos.shim.bridge.OHBridge.surfaceFlush(surf);
                startupLog("[WestlakeLauncher] Real icons frame rendered! (" + realIconsPng.length + " bytes)");
            } catch (Throwable t) {
                startupLog("[WestlakeLauncher] Real icons render error", t);
            }
        }

        boolean needsRender = (initialActivity != null && !isHomeDashboardActivity(initialActivity));
        sDisableHostInputPolling = false;
        long downTime = 0;
        int lastTouchY = 0;
        int scrollOffset = 0;
        int totalDragDistance = 0;
        android.view.View lastDecorView = null;

        Activity current = initialActivity; // prefer WAT-created activity
        if (current == null) current = am.getResumedActivity();
        startupLog("[WestlakeLauncher] renderLoop current="
                + (current != null ? current.getClass().getName() : "null"));

        while (true) {
            try {
                Thread.sleep(1);
            } catch (InterruptedException e) {
                break;
            }
            try {
                int pumped = android.os.Looper.pumpMessages();
                if (pumped > 0) {
                    needsRender = true;
                    if (frameCount < 20) {
                        startupLog("[WestlakeLauncher] renderLoop pumped messages=" + pumped);
                    }
                }
            } catch (Throwable pumpError) {
                if (frameCount < 5) {
                    logThrowableFrames("[WestlakeLauncher] renderLoop pump error", pumpError, 12);
                }
            }
            if (android.app.WestlakeActivityThread.pendingDashboardClass != null) {
                startupLog("[WestlakeLauncher] renderLoop pending dashboard handoff");
                renderLoop(current, am);
                return;
            }
            if (current == null) {
                startupLog("[WestlakeLauncher] No resumed activity, exiting");
                break;
            }

            if (!sDisableHostInputPolling) {
                // Check for text input from host (long-press dialog)
                byte[] textBuf = canOpenFile(textPath) ? tryReadFileBytes(textPath) : null;
                if (textBuf != null && textBuf.length > 0) {
                    try {
                        int textHash = java.util.Arrays.hashCode(textBuf);
                        if (textBuf.length != lastTextSize || textHash != lastTextHash) {
                            lastTextSize = textBuf.length;
                            lastTextHash = textHash;
                            String inputText = utf8BytesToString(textBuf, "").trim();
                            if (inputText.length() > 0) {
                                android.view.View decor = null;
                                try { decor = current.getWindow().getDecorView(); } catch (Exception e5) {}
                                if (decor != null) {
                                    android.widget.EditText et = findEditText(decor);
                                    if (et != null) {
                                        et.setText(inputText);
                                        startupLog("[WestlakeLauncher] Text input: '" + inputText + "' -> " + et);
                                        needsRender = true;
                                    } else {
                                        startupLog("[WestlakeLauncher] Text input: no EditText found");
                                    }
                                }
                            }
                        }
                    } catch (Exception e5) {
                        startupLog("[WestlakeLauncher] Text input error: " + e5);
                    }
                } else {
                    lastTextSize = -1;
                    lastTextHash = 0;
                }

                // Check for touch events
                byte[] buf = canOpenFile(touchPath) ? tryReadFileBytes(touchPath) : null;
                if (buf != null && buf.length >= 16) {
                    try {
                        java.nio.ByteBuffer bb = java.nio.ByteBuffer.wrap(buf, 0, 16);
                        bb.order(java.nio.ByteOrder.LITTLE_ENDIAN);
                        int action = bb.getInt();
                        int x = bb.getInt();
                        int y = bb.getInt();
                        int seq = bb.getInt();

                        if (seq != lastTouchSeq) {
                            lastTouchSeq = seq;

                            long now = System.currentTimeMillis();
                            boolean dashboardTouch = isHomeDashboardActivity(current);
                            if (action == 0) {
                                downTime = now;
                                lastTouchY = y;
                                totalDragDistance = 0;
                                startupLog("[WestlakeLauncher] Touch DOWN at (" + x + "," + y + ")");
                                if (dashboardTouch) {
                                    logMcdDashboardTouchRoute("down", x, y, scrollOffset);
                                } else {
                                    current.dispatchTouchEvent(
                                        android.view.MotionEvent.obtain(downTime, now, 0, (float)x, (float)y, 0));
                                }
                                if (!dashboardTouch) {
                                    needsRender = true;
                                }
                            } else if (action == 2) {
                                if (downTime == 0) downTime = now;
                                int deltaY = lastTouchY - y;
                                lastTouchY = y;
                                totalDragDistance += Math.abs(deltaY);

                                android.view.View decor = null;
                                try { decor = current.getWindow().getDecorView(); } catch (Exception e3) {}
                                if (decor != null) {
                                    int maxScroll = SURFACE_HEIGHT * 2;
                                    scrollOffset += deltaY;
                                    if (scrollOffset < 0) scrollOffset = 0;
                                    if (scrollOffset > maxScroll) scrollOffset = maxScroll;
                                    if (isHomeDashboardActivity(current)) {
                                        applyMcdDashboardScrollOffset(current, scrollOffset);
                                    } else {
                                        decor.scrollTo(0, scrollOffset);
                                    }
                                }

                                if (dashboardTouch) {
                                    logMcdDashboardTouchRoute("move", x, y, scrollOffset);
                                } else {
                                    current.dispatchTouchEvent(
                                        android.view.MotionEvent.obtain(downTime, now, 2, (float)x, (float)y, 0));
                                }
                                if (!dashboardTouch) {
                                    needsRender = true;
                                }
                            } else if (action == 1) {
                                if (downTime == 0) {
                                    downTime = now;
                                    lastTouchY = y;
                                    totalDragDistance = 0;
                                    if (dashboardTouch) {
                                        logMcdDashboardTouchRoute("synthetic_down", x, y,
                                                scrollOffset);
                                    }
                                }
                                int finalDeltaY = lastTouchY - y;
                                if (Math.abs(finalDeltaY) > 20) {
                                    int maxScroll = SURFACE_HEIGHT * 2;
                                    scrollOffset += finalDeltaY;
                                    if (scrollOffset < 0) scrollOffset = 0;
                                    if (scrollOffset > maxScroll) scrollOffset = maxScroll;
                                    if (isHomeDashboardActivity(current)) {
                                        applyMcdDashboardScrollOffset(current, scrollOffset);
                                    } else {
                                        android.view.View decor = null;
                                        try { decor = current.getWindow().getDecorView(); } catch (Exception e3) {}
                                        if (decor != null) {
                                            decor.scrollTo(0, scrollOffset);
                                        }
                                    }
                                    if (dashboardTouch) {
                                        logMcdDashboardTouchRoute("final_move", x, y, scrollOffset);
                                    } else {
                                        current.dispatchTouchEvent(
                                                android.view.MotionEvent.obtain(downTime, now, 2,
                                                        (float)x, (float)y, 0));
                                    }
                                    totalDragDistance += Math.abs(finalDeltaY);
                                }
                                boolean candidateTap = totalDragDistance < 20;
                                boolean rawUpDispatchHandled = false;
                                boolean fallbackHit = false;

                                startupLog("[WestlakeLauncher] Touch UP at (" + x + "," + y + ")");
                                if (dashboardTouch) {
                                    logMcdDashboardTouchRoute("up", x, y, scrollOffset);
                                } else {
                                    rawUpDispatchHandled = current.dispatchTouchEvent(
                                        android.view.MotionEvent.obtain(downTime, now, 1, (float)x, (float)y, 0));
                                    String marker = "phase=up"
                                            + " activity=" + safeMarkerToken(current.getClass().getName())
                                            + " handled=" + boolToken(rawUpDispatchHandled)
                                            + " x=" + intAscii(x)
                                            + " y=" + intAscii(y)
                                            + " projectedPoint=" + boolToken(
                                                    isOrderProductDetailsActivity(current)
                                                            && isMcdOrderPdpProjectedControlPoint(x, y));
                                    startupLog("[WestlakeLauncher] WESTLAKE_HOST_TOUCH_DISPATCH " + marker);
                                    appendCutoffCanaryMarker("WESTLAKE_HOST_TOUCH_DISPATCH " + marker);
                                }
                                needsRender = true;

                                if (dashboardTouch && Math.abs(finalDeltaY) <= 20) {
                                    candidateTap = true;
                                    String marker = "x=" + intAscii(x)
                                            + " y=" + intAscii(y)
                                            + " finalDeltaY=" + intAscii(finalDeltaY)
                                            + " totalDragDistance=" + intAscii(totalDragDistance)
                                            + " scrollOffset=" + intAscii(scrollOffset);
                                    startupLog("[WestlakeLauncher] MCD_DASH_UP_ROUTE_GATE " + marker);
                                    appendCutoffCanaryMarker("MCD_DASH_UP_ROUTE_GATE " + marker);
                                }
                                boolean pdpTouch = !dashboardTouch
                                        && isOrderProductDetailsActivity(current);
                                if (candidateTap && (!rawUpDispatchHandled || pdpTouch)) {
                                    fallbackHit = routeGenericHitClick(current, x, y);
                                    if (!fallbackHit
                                            && routeDashboardFallbackTouch(current, action,
                                                    x, y + scrollOffset)) {
                                        startupLog("[WestlakeLauncher] Dashboard fallback direct touch routed");
                                    }
                                    if (pdpTouch) {
                                        String marker = "phase=tap_generic"
                                                + " handled=" + boolToken(fallbackHit)
                                                + " rawUpHandled=" + boolToken(rawUpDispatchHandled)
                                                + " x=" + intAscii(x)
                                                + " y=" + intAscii(y)
                                                + " projectedPoint=" + boolToken(
                                                        isMcdOrderPdpProjectedControlPoint(x, y));
                                        startupLog("[WestlakeLauncher] MCD_ORDER_PDP_GENERIC_ROUTE "
                                                + marker);
                                        appendCutoffCanaryMarker("MCD_ORDER_PDP_GENERIC_ROUTE "
                                                + marker);
                                    }
                                }
                                android.view.View newDecor = null;
                                try { newDecor = current.getWindow().getDecorView(); } catch (Exception e4) {}
                                if (newDecor != null && newDecor != lastDecorView) {
                                    newDecor.scrollTo(0, 0);
                                    scrollOffset = 0;
                                    lastDecorView = newDecor;
                                }
                                downTime = 0;
                            }
                        }
                    } catch (Exception e) {
                        startupLog("[WestlakeLauncher] touch read error: " + e);
                    }
                }
            }

            if (needsRender) {
                Activity next = current;
                Activity resumed = null;
                try { resumed = am.getResumedActivity(); } catch (Throwable ignored) {}
                if (shouldAdoptResumedActivity(current, resumed)) {
                    next = resumed;
                }
                if (next != null) {
                    boolean dashboardActivity = isHomeDashboardActivity(next);
                    if (next != current) {
                        if (!dashboardActivity) {
                            try { next.onSurfaceCreated(0L, SURFACE_WIDTH, SURFACE_HEIGHT); } catch (Exception e2) {}
                        }
                        startupLog("[WestlakeLauncher] Navigated to " + next.getClass().getSimpleName());
                        current = next;
                    }
                    if (dashboardActivity) {
                        if (!FRAMEWORK_POLICY_WESTLAKE_ONLY.equals(frameworkPolicyValue())
                                || !writeStrictStandaloneViewFrame(current, "dashboard-renderLoop")) {
                            try { current.renderFrame(); } catch (Exception e2) {
                                if (frameCount < 5) startupLog("[WestlakeLauncher] dashboard renderFrame error", e2);
                            }
                        }
                    } else {
                        if (!FRAMEWORK_POLICY_WESTLAKE_ONLY.equals(frameworkPolicyValue())
                                || !writeStrictStandaloneViewFrame(current, "renderLoop")) {
                            try { current.renderFrame(); } catch (Exception e2) {
                                if (frameCount < 5) startupLog("[WestlakeLauncher] renderFrame error", e2);
                                if (frameCount < 2) {
                                    logThrowableFrames("[WestlakeLauncher] renderFrame", e2, 12);
                                }
                            }
                        }
                    }
                }
                needsRender = false;
            }

            frameCount++;
        }
        startupLog("[WestlakeLauncher] Render loop ended");
    }

    private static void runStrictStandaloneMainLoop(Activity initialActivity, MiniActivityManager am) {
        startupLog("PF301 strict launcher keepalive pump begin");
        Activity current = initialActivity;
        int tick = 0;
        int pumpLogCount = 0;
        int renderErrorLogCount = 0;
        long loopStartMs = java.lang.System.currentTimeMillis();
        while (true) {
            try {
                if (shouldForceMcdDashboardAfterSplash(current, tick, loopStartMs)) {
                    android.app.WestlakeActivityThread.pendingDashboardClass =
                            "com.mcdonalds.homedashboard.activity.HomeDashboardActivity";
                    startupLog("PF301 strict launcher queued McD dashboard before splash pump");
                    renderLoop(current, am);
                    return;
                }

                int pumped = 0;
                try {
                    pumped = android.os.Looper.pumpMessages();
                } catch (Throwable pumpError) {
                    if (tick < 5) {
                        startupLog("PF301 strict launcher pump threw", pumpError);
                    }
                }
                if (pumped > 0 && pumpLogCount < 20) {
                    startupLog("PF301 strict launcher pumped messages=" + pumped);
                    pumpLogCount++;
                }

                if (android.app.WestlakeActivityThread.pendingDashboardClass != null) {
                    startupLog("PF301 strict launcher pending dashboard handoff");
                    renderLoop(current, am);
                    return;
                }

                Activity resumed = null;
                try {
                    resumed = am != null ? am.getResumedActivity() : null;
                } catch (Throwable ignored) {
                }
                if (shouldAdoptResumedActivity(current, resumed)) {
                    current = resumed;
                    startupLog("PF301 strict launcher resumed="
                            + current.getClass().getName());
                    try {
                        current.onSurfaceCreated(0L, SURFACE_WIDTH, SURFACE_HEIGHT);
                    } catch (Throwable surfaceError) {
                        startupLog("PF301 strict launcher resumed surface threw", surfaceError);
                    }
                }

                if (current != null && (pumped > 0 || (tick % 10) == 0)) {
                    if (!writeStrictStandaloneViewFrame(current,
                            pumped > 0 ? "pumped" : "tick")) {
                        try {
                            current.renderFrame();
                        } catch (Throwable renderError) {
                            if (renderErrorLogCount < 5) {
                                startupLog("PF301 strict launcher render tick threw", renderError);
                                renderErrorLogCount++;
                            }
                        }
                    }
                }
                if (shouldForceMcdDashboardAfterSplash(current, tick, loopStartMs)) {
                    android.app.WestlakeActivityThread.pendingDashboardClass =
                            "com.mcdonalds.homedashboard.activity.HomeDashboardActivity";
                    startupLog("PF301 strict launcher queued McD dashboard after splash stall");
                    renderLoop(current, am);
                    return;
                }
                Thread.sleep(100);
                tick++;
            } catch (InterruptedException e) {
                startupLog("PF301 strict launcher keepalive interrupted");
                break;
            }
        }
    }

    private static boolean shouldForceMcdDashboardAfterSplash(
            Activity current, int tick, long loopStartMs) {
        if (current == null
                || !isMcdonaldsSplashActivity(current)
                || android.app.WestlakeActivityThread.pendingDashboardClass != null) {
            return false;
        }
        long elapsed = 0L;
        try {
            elapsed = java.lang.System.currentTimeMillis() - loopStartMs;
        } catch (Throwable ignored) {
        }
        return tick >= 8 || elapsed >= 850L;
    }

    private static boolean shouldDeferMcdDashboardResumeForFirstFrame(
            Activity dashboard, Activity previous) {
        if (!FRAMEWORK_POLICY_WESTLAKE_ONLY.equals(frameworkPolicyValue())) {
            return false;
        }
        if (!isHomeDashboardActivity(dashboard)) {
            return false;
        }
        return !isHomeDashboardActivity(previous);
    }

    private static void startDeferredMcdDashboardResume(final Activity dashboard) {
        if (!isHomeDashboardActivity(dashboard)) {
            return;
        }
        Thread resumeThread = new Thread(new Runnable() {
            @Override
            public void run() {
                try {
                    Thread.sleep(250L);
                } catch (InterruptedException ignored) {
                }
                try {
                    startupLog("[WestlakeLauncher] Dashboard deferred resume begin");
                    appendCutoffCanaryMarker("MCD_DASH_RESUME_ASYNC_BEGIN");
                    android.app.WestlakeActivityThread.currentActivityThread()
                            .performResumeActivity(dashboard);
                    startupLog("[WestlakeLauncher] Dashboard deferred resume done");
                    appendCutoffCanaryMarker("MCD_DASH_RESUME_ASYNC_DONE");
                } catch (Throwable resumeError) {
                    startupLog("[WestlakeLauncher] Dashboard deferred resume error", resumeError);
                    logThrowableFrames("[WestlakeLauncher] Dashboard deferred resume",
                            resumeError, 12);
                    appendCutoffCanaryMarker("MCD_DASH_RESUME_ASYNC_ERROR "
                            + safeMarkerToken(throwableTag(resumeError)));
                }
            }
        }, "McdDashboardResumeAfterFirstFrame");
        resumeThread.setDaemon(true);
        try {
            resumeThread.start();
            startupLog("[WestlakeLauncher] Dashboard deferred resume scheduled");
        } catch (Throwable startError) {
            startupLog("[WestlakeLauncher] Dashboard deferred resume start error", startError);
        }
    }

    private static boolean isMcdonaldsSplashActivity(Activity activity) {
        if (!isMcdonaldsActivity(activity)) {
            return false;
        }
        try {
            return activity.getClass().getName().endsWith(".SplashActivity");
        } catch (Throwable ignored) {
            return false;
        }
    }

    private static boolean writeStrictStandaloneViewFrame(Activity activity, String reason) {
        try {
            int height = isMcdonaldsActivity(activity) ? YELP_SURFACE_HEIGHT : SURFACE_HEIGHT;
            android.view.View decor = activity != null && activity.getWindow() != null
                    ? activity.getWindow().getDecorView() : null;
            if (decor == null) {
                appendCutoffCanaryMarker("STRICT_VIEW_FRAME_FAIL reason="
                        + safeMarkerToken(reason) + " err=no_decor");
                return false;
            }
            android.view.View renderRoot = decor;
            if (isHomeDashboardActivity(activity)) {
                renderRoot = selectMcdDashboardRenderRoot(activity, decor);
                layoutMcdDashboardStrictFrame(renderRoot, SURFACE_WIDTH, height, reason);
                dispatchViewTreeBeforeStrictRender(renderRoot, SURFACE_WIDTH, height,
                        reason, true);
                int sectionsId = resolveAppResourceId(activity, "id", "sections_container");
                int homeId = resolveAppResourceId(activity, "id", "home_dashboard_container");
                logDashboardRootProbe("post-layout", activity, decor,
                        safeFindViewById(decor, sectionsId, "sections_container.post_layout"),
                        safeFindViewById(decor, homeId, "home_dashboard_container.post_layout"),
                        renderRoot);
            } else if (isOrderProductDetailsActivity(activity)) {
                prepareMcdPdpForStrictFrame(activity, decor, height, reason);
                renderRoot = selectMcdOrderProductDetailRenderRoot(activity, decor, height);
                dispatchViewTreeBeforeStrictRender(renderRoot, SURFACE_WIDTH, height,
                        reason, false);
            } else {
                layoutDecorForHeight(activity, height, "Strict standalone generic");
                dispatchViewTreeBeforeStrictRender(renderRoot, SURFACE_WIDTH, height,
                        reason, false);
            }
            java.io.ByteArrayOutputStream ops = new java.io.ByteArrayOutputStream(32768);
            ShowcaseTreeStats stats = new ShowcaseTreeStats();
            stats.mcdDashboardFrame = isHomeDashboardActivity(activity);
            stats.mcdOrderPdpFrame = isOrderProductDetailsActivity(activity);
            appendCutoffCanaryMarker("STRICT_VIEW_FRAME_STAGE reason="
                    + safeMarkerToken(reason) + " stage=before_tree");
            if (isHomeDashboardActivity(activity)) {
                startupLog("[WestlakeLauncher] STRICT_VIEW_FRAME_STAGE reason="
                        + reason + " stage=before_tree");
            }
            int renderOffsetY = stats.mcdDashboardFrame ? -sMcdDashboardProjectionScrollOffset : 0;
            renderShowcaseView(ops, renderRoot, 0, renderOffsetY, 0, stats, height);
            appendCutoffCanaryMarker("STRICT_VIEW_FRAME_STAGE reason="
                    + safeMarkerToken(reason) + " stage=after_tree bytes="
                    + intAscii(ops.size())
                    + " rows=" + intAscii(stats.genericListRows));
            if (isHomeDashboardActivity(activity)) {
                startupLog("[WestlakeLauncher] STRICT_VIEW_FRAME_STAGE reason="
                        + reason + " stage=after_tree bytes=" + ops.size()
                        + " rows=" + stats.genericListRows);
            }
            if (isHomeDashboardActivity(activity) && stats.genericListRows < 3) {
                appendCutoffCanaryMarker("STRICT_VIEW_FRAME_STAGE reason="
                        + safeMarkerToken(reason) + " stage=before_overlay");
                startupLog("[WestlakeLauncher] STRICT_VIEW_FRAME_STAGE reason="
                        + reason + " stage=before_overlay");
                renderMcdRecyclerAdapterOverlays(ops, renderRoot, stats, height);
                appendCutoffCanaryMarker("STRICT_VIEW_FRAME_STAGE reason="
                        + safeMarkerToken(reason) + " stage=after_overlay bytes="
                        + intAscii(ops.size())
                        + " rows=" + intAscii(stats.genericListRows));
                startupLog("[WestlakeLauncher] STRICT_VIEW_FRAME_STAGE reason="
                        + reason + " stage=after_overlay bytes=" + ops.size()
                        + " rows=" + stats.genericListRows);
            }
            if (isHomeDashboardActivity(activity)) {
                int beforeDashboardProjection = ops.size();
                renderMcdDashboardProjection(ops, renderRoot, stats, height);
                appendCutoffCanaryMarker("MCD_DASH_PROJECTED_FRAME reason="
                        + safeMarkerToken(reason)
                        + " before=" + intAscii(beforeDashboardProjection)
                        + " after=" + intAscii(ops.size())
                        + " rows=" + intAscii(stats.genericListRows)
                        + " rowImages=" + intAscii(stats.genericListImages)
                        + " rowImageBytes=" + intAscii(stats.genericListImageBytes));
            }
            if (isOrderProductDetailsActivity(activity)) {
                int beforePdpProjection = ops.size();
                renderMcdOrderPdpProjection(ops, renderRoot, stats, height);
                appendCutoffCanaryMarker("MCD_ORDER_PDP_PROJECTED_FRAME reason="
                        + safeMarkerToken(reason)
                        + " before=" + intAscii(beforePdpProjection)
                        + " after=" + intAscii(ops.size())
                        + " texts=" + intAscii(stats.texts)
                        + " images=" + intAscii(stats.images));
            }
            byte[] data = ops.toByteArray();
            synchronized (sStrictFrameOutputLock) {
                java.io.OutputStream out = strictFrameOutputStream();
                if (out == null) {
                    appendCutoffCanaryMarker("STRICT_VIEW_FRAME_FAIL reason="
                            + safeMarkerToken(reason) + " err=no_frame_output");
                    return false;
                }
                writeIntLe(out, 0x444C5354);
                writeIntLe(out, data.length);
                out.write(data);
                out.flush();
            }
            appendCutoffCanaryMarker("STRICT_VIEW_FRAME_OK reason="
                    + safeMarkerToken(reason)
                    + " activity=" + safeMarkerToken(activity.getClass().getName())
                    + " bytes=" + intAscii(data.length)
                    + " views=" + intAscii(stats.views)
                    + " texts=" + intAscii(stats.texts)
                    + " buttons=" + intAscii(stats.buttons)
                    + " images=" + intAscii(stats.images)
                    + " lists=" + intAscii(stats.listViews)
                    + " rows=" + intAscii(stats.genericListRows)
                    + " rowImages=" + intAscii(stats.genericListImages)
                    + " rowImageBytes=" + intAscii(stats.genericListImageBytes)
                    + " recyclerOverlayRows=" + intAscii(stats.recyclerOverlayRows)
                    + " height=" + intAscii(height));
            if (isHomeDashboardActivity(activity)) {
                startupLog("[WestlakeLauncher] Strict dashboard frame reason=" + reason
                        + " root=" + renderRoot.getClass().getName()
                        + " bytes=" + data.length
                        + " views=" + stats.views
                        + " texts=" + stats.texts
                        + " buttons=" + stats.buttons
                        + " images=" + stats.images
                        + " rows=" + stats.genericListRows
                        + " rowImages=" + stats.genericListImages
                        + " rowImageBytes=" + stats.genericListImageBytes
                        + " overlays=" + stats.recyclerOverlayCount);
            } else if (isOrderProductDetailsActivity(activity)) {
                String markerValue = "reason=" + safeMarkerToken(reason)
                        + " root=" + safeMarkerToken(safeViewSummary(renderRoot))
                        + " bytes=" + intAscii(data.length)
                        + " views=" + intAscii(stats.views)
                        + " texts=" + intAscii(stats.texts)
                        + " buttons=" + intAscii(stats.buttons)
                        + " images=" + intAscii(stats.images)
                        + " rows=" + intAscii(stats.genericListRows)
                        + " tree=" + safeMarkerToken(safeViewTreeSample(renderRoot, 0, 10));
                startupLog("[WestlakeLauncher] Strict McD order PDP frame " + markerValue);
                appendCutoffCanaryMarker("MCD_ORDER_PDP_STRICT_FRAME " + markerValue);
            } else if (isMcdonaldsActivity(activity) && sMcdNonDashboardFrameProbeCount < 20) {
                sMcdNonDashboardFrameProbeCount++;
                startupLog("[WestlakeLauncher] Strict McD frame reason=" + reason
                        + " activity=" + activity.getClass().getName()
                        + " root=" + safeViewSummary(renderRoot)
                        + " bytes=" + data.length
                        + " views=" + stats.views
                        + " texts=" + stats.texts
                        + " buttons=" + stats.buttons
                        + " images=" + stats.images
                        + " rows=" + stats.genericListRows
                        + " tree=" + safeViewTreeSample(renderRoot, 0, 8));
            }
            return data.length > 0;
        } catch (Throwable t) {
            startupLog("[WestlakeLauncher] Strict standalone view frame error", t);
            logThrowableFrames("[WestlakeLauncher] Strict standalone view frame", t, 12);
            appendCutoffCanaryMarker("STRICT_VIEW_FRAME_FAIL err="
                    + t.getClass().getName());
            return false;
        }
    }

    private static boolean isMcdonaldsActivity(Activity activity) {
        if (activity == null) {
            return false;
        }
        try {
            String name = activity.getClass().getName();
            return name != null && name.startsWith("com.mcdonalds.");
        } catch (Throwable ignored) {
            return false;
        }
    }

